<?php require_once __DIR__.'/includes/functions.php'; require_role(['admin','teacher']); $page_title='Môn học';
if(isset($_GET['delete'])){$id=(int)$_GET['delete'];$st=db()->prepare('SELECT name FROM subjects WHERE id=?');$st->execute([$id]);$name=(string)$st->fetchColumn();db()->prepare('DELETE FROM subjects WHERE id=?')->execute([$id]);log_activity('delete','subject',$id,'Đã xóa môn học: '.($name?:('#'.$id))); flash('Đã xóa môn học'); redirect('subjects.php');}
if($_SERVER['REQUEST_METHOD']==='POST'){ $id=(int)($_POST['id']??0); $name=post('name'); if($id){db()->prepare('UPDATE subjects SET name=? WHERE id=?')->execute([$name,$id]);log_activity('update','subject',$id,'Đã cập nhật môn học: '.$name);} else {db()->prepare('INSERT INTO subjects(name) VALUES(?)')->execute([$name]);log_activity('create','subject',(int)db()->lastInsertId(),'Đã tạo môn học: '.$name);} flash('Đã lưu môn học'); redirect('subjects.php');}
$edit=null;if(isset($_GET['edit'])){$st=db()->prepare('SELECT * FROM subjects WHERE id=?');$st->execute([(int)$_GET['edit']]);$edit=$st->fetch();}
$rows=fetch_subjects(); include __DIR__.'/includes/header.php'; ?>
<div class="grid grid-2"><div class="card"><h2><?= $edit?'Sửa':'Thêm' ?> môn học</h2><form method="post"><input type="hidden" name="id" value="<?= e($edit['id']??0) ?>"><label>Tên môn học</label><input name="name" required value="<?= e($edit['name']??'') ?>"><br><br><button class="btn primary">Lưu</button></form></div><div class="card"><h2>Danh sách môn học</h2><table class="table"><?php foreach($rows as $r): ?><tr><td><?= e($r['name']) ?></td><td class="actions"><a class="btn ghost" href="?edit=<?= $r['id'] ?>">Sửa</a><a class="btn danger" data-confirm="Xóa môn sẽ xóa bài và câu hỏi liên quan?" href="?delete=<?= $r['id'] ?>">Xóa</a></td></tr><?php endforeach; ?></table></div></div>
<?php include __DIR__.'/includes/footer.php'; ?>
